import pyomo.environ as pyo
from pyomo.environ import ConcreteModel, Var, Objective, Constraint, NonNegativeIntegers, minimize, SolverFactory

def solve():
    model = ConcreteModel()

    # Define sets
    production_lines = ['A', 'B']
    tasks = [1, 2, 3]

    # Define parameters
    min_energy_consumption = {1: 10, 2: 15, 3: 12}
    max_energy_consumption = {1: 20, 2: 25, 3: 22}
    energy_cost_per_unit = {1: 5, 2: 4, 3: 6}
    production_cost_per_unit = {1: 30, 2: 35, 3: 32}
    production_quantity = {1: 300, 2: 200, 3: 250}
    production_capacity = {'A': 400, 'B': 350}

    # Define decision variables
    model.x = Var(production_lines, tasks, domain=NonNegativeIntegers)

    # Define objective function
    def objective_rule(m):
        return sum(
            energy_cost_per_unit[j] * min_energy_consumption[j] * m.x[i, j] +
            production_cost_per_unit[j] * m.x[i, j]
            for i in production_lines for j in tasks
        )
    model.obj = Objective(rule=objective_rule, sense=minimize)

    # Define production quantity constraints
    def production_quantity_rule(m, j):
        return sum(m.x[i, j] for i in production_lines) == production_quantity[j]
    model.production_quantity = Constraint(tasks, rule=production_quantity_rule)

    # Define production capacity constraints
    def production_capacity_rule(m, i):
        return sum(m.x[i, j] for j in tasks) <= production_capacity[i]
    model.production_capacity = Constraint(production_lines, rule=production_capacity_rule)

    # Define energy consumption constraints
    def energy_consumption_rule(m, i, j):
        return min_energy_consumption[j] * m.x[i, j] <= max_energy_consumption[j] * m.x[i, j]
    model.energy_consumption = Constraint(production_lines, tasks, rule=energy_consumption_rule)

    # Solve the model
    solver = SolverFactory('glpk')  # You can choose another solver if preferred
    solver.solve(model, tee=False)

    # Return the optimized objective value
    return pyo.value(model.obj)
